import Layer from"./Layer.js";import WebGLPointsLayerRenderer from"../renderer/webgl/PointsLayer.js";import{assign}from"../obj.js";import{parseLiteralStyle}from"../webgl/ShaderBuilder.js";class WebGLPointsLayer extends Layer{constructor(e){super(assign({},e)),this.parseResult_=parseLiteralStyle(e.style),this.styleVariables_=e.style.variables||{},this.hitDetectionDisabled_=!!e.disableHitDetection}createRenderer(){return new WebGLPointsLayerRenderer(this,{vertexShader:this.parseResult_.builder.getSymbolVertexShader(),fragmentShader:this.parseResult_.builder.getSymbolFragmentShader(),hitVertexShader:!this.hitDetectionDisabled_&&this.parseResult_.builder.getSymbolVertexShader(!0),hitFragmentShader:!this.hitDetectionDisabled_&&this.parseResult_.builder.getSymbolFragmentShader(!0),uniforms:this.parseResult_.uniforms,attributes:this.parseResult_.attributes})}updateStyleVariables(e){assign(this.styleVariables_,e),this.changed()}}export default WebGLPointsLayer;